 {"id":"charmed_rust-hh4","title":"Implement Authentication Handlers","description":"# Implement Authentication Handlers

## Objective
Implement password and public key authentication handlers with pluggable authentication backends.

## Implementation Details

### Authentication Trait
```rust
use async_trait::async_trait;

#[async_trait]
pub trait Authenticator: Send + Sync {
    /// Authenticate with username and password
    async fn auth_password(&self, user: &str, password: &str) -> AuthResult;

    /// Authenticate with public key
    async fn auth_publickey(&self, user: &str, key: &PublicKey) -> AuthResult;

    /// Check if authentication method is supported
    fn supports_method(&self, method: AuthMethod) -> bool;
}

pub enum AuthResult {
    Accept,
    Reject,
    Partial { remaining_methods: Vec<AuthMethod> },
}

pub enum AuthMethod {
    Password,
    PublicKey,
    KeyboardInteractive,
}
```

### Default Authenticators
```rust
/// File-based authorized_keys authenticator
pub struct AuthorizedKeysAuth {
    keys_dir: PathBuf,
}

impl AuthorizedKeysAuth {
    pub fn new(keys_dir: impl Into<PathBuf>) -> Self {
        Self { keys_dir: keys_dir.into() }
    }

    fn load_user_keys(&self, user: &str) -> Result<Vec<PublicKey>> {
        let path = self.keys_dir.join(user).join("authorized_keys");
        log::debug!("Loading authorized keys from {:?}", path);
        // Parse OpenSSH authorized_keys format
    }
}

#[async_trait]
impl Authenticator for AuthorizedKeysAuth {
    async fn auth_publickey(&self, user: &str, key: &PublicKey) -> AuthResult {
        match self.load_user_keys(user) {
            Ok(keys) if keys.iter().any(|k| k == key) => {
                log::info!("Public key authentication successful for user '{}'", user);
                AuthResult::Accept
            }
            Ok(_) => {
                log::warn!("Public key not found for user '{}'", user);
                AuthResult::Reject
            }
            Err(e) => {
                log::error!("Failed to load keys for '{}': {}", user, e);
                AuthResult::Reject
            }
        }
    }

    async fn auth_password(&self, _user: &str, _password: &str) -> AuthResult {
        AuthResult::Reject // Not supported
    }

    fn supports_method(&self, method: AuthMethod) -> bool {
        matches!(method, AuthMethod::PublicKey)
    }
}
```

### Integration with russh Handler
```rust
impl russh::server::Handler for ConnectionHandler {
    async fn auth_password(
        &mut self,
        user: &str,
        password: &str,
    ) -> Result<Auth, Self::Error> {
        log::debug!("Password auth attempt for user '{}'", user);

        match self.authenticator.auth_password(user, password).await {
            AuthResult::Accept => {
                self.authenticated_user = Some(user.to_string());
                Ok(Auth::Accept)
            }
            AuthResult::Reject => {
                log::warn!("Password auth failed for user '{}'", user);
                Ok(Auth::Reject { 
                    proceed_with_methods: Some(MethodSet::PUBLICKEY) 
                })
            }
            AuthResult::Partial { .. } => {
                Ok(Auth::Partial { 
                    name: "".into(),
                    instructions: "".into(),
                    prompts: vec![]
                })
            }
        }
    }

    async fn auth_publickey(
        &mut self,
        user: &str,
        public_key: &PublicKey,
    ) -> Result<Auth, Self::Error> {
        log::debug!("Public key auth attempt for user '{}'", user);
        // Similar implementation
    }
}
```

