+        assert_eq!(truncate_content("日本語", 5), "日本…"); // 4 for 日本 + 1 for ellipsis
+        assert_eq!(truncate_content("日本語", 6), "日本語"); // Exactly fits
+
+        // Mixed content
+        assert_eq!(truncate_content("Hi日本", 5), "Hi日…"); // 2 + 2 + 1
+    }
